sql:
SELECT c.company_name, t.transaction_amount
FROM transactions t
INNER JOIN companies c ON t.company_id = c.company_id;

SELECT company_id, COUNT(transaction_id) AS transaction_count
FROM transactions
GROUP BY company_id;

SELECT insider_name
FROM insider_relationships
WHERE status = 'Active';

SELECT transaction_id, user_id, access_date, access_type, ip_address, session_id
FROM access_logs
ORDER BY access_date DESC;

external_knowledge:
Large corporations: companies with a market capitalization greater than 100 billion;
Successful deals: transactions marked as 'Completed' in the database;
Exercise deals: transactions specifically categorized as 'Exercise' type;
Significant transaction sums: sums over 10 million are considered significant in this context.
